// Payload de Zadarma o CRM al detectar llamada perdida
const body = $input.first().json.body || $input.first().json;

const callerNumber = body.caller_number || body.caller_id   || body.from         || 'Desconocido';
const callerName   = body.caller_name   || body.lead_name   || body.contact_name || '';
const agentName    = body.agent_name    || body.asesor      || body.sip_id       || 'Sin asignar';
const callTime     = body.call_time     || body.start_time  || body.called_at    || '';

const now = new Date();
const hora = callTime
  ? new Date(callTime).toLocaleTimeString('es-CO', { hour: '2-digit', minute: '2-digit', timeZone: 'America/Bogota' })
  : now.toLocaleTimeString('es-CO', { hour: '2-digit', minute: '2-digit', timeZone: 'America/Bogota' });

const nameDisplay = callerName ? `${callerName} (${callerNumber})` : callerNumber;

const message = [
  '🔴 *ALERTA - LLAMADA PERDIDA*',
  '',
  `📞 *De:* ${nameDisplay}`,
  `🧑‍💼 *Asesor:* ${agentName}`,
  `🕐 *Hora:* ${hora} (Col)`,
  '',
  '⚠️ _Por favor retornar la llamada lo antes posible_',
].join('\n');

return [{ json: { message, callerNumber, agentName } }];
